package be.schaubroeck.lpb.rkm.rekenmotor.rsz.pensioenpijler2.validatie;

import be.schaubroeck.lpb.rkm.begroting.logger.BegrotingQueueCalculateFailureLogger;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.CategorieFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.StatuutFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.WerknemersKengetalFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.WerknemersKengetalMapperFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.pensioenpijler2.PensioenPijler2TypeBijdrage;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.DmfapplBasisBijdrage;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplNotieGepens;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.VrijstelPens2;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.Categorie;
import be.schaubroeck.lpb.tools.rsz.Statuut;
import be.schaubroeck.lpb.tools.service.DmfapplBasisBijdrageService;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.List;

public class PensioenPijler2Validator2010 implements PensioenPijler2Validator {
    private static final LocalDate START_BONUSBIJDRAGE = new LocalDate(2014, 1, 1);
    private static final LocalDate VANAF_2007 = new LocalDate(2007, 1, 1);
    private static final LocalDate VANAF_2010 = new LocalDate(2010, 1, 1);
    private static final LocalDate START_PENS2_GEZONDHEIDS_SECTOR = new LocalDate(2011, 4, 1);

    private static final int DOELGROEP_PENS2_STANDAARD = 1;
    private static final int DOELGROEP_PENS2_OOK_GEZONDHEID_SECTOR = 2;
    private final ConstantManager constantManager;
    private final DmfapplBasisBijdrageService dmfapplBasisBijdrageService;

    private final Opper opper;
    private final RekenTijd rekenTijd;
    private final RegulManager regulManager;


    private final LocalDate beginDatum;
    private final LocalDate eindDatum;
    private final VrijstelPens2 vrijstellingTweedePensioenpijler;

    public PensioenPijler2Validator2010(
            ConstantManager constantManager, DmfapplBasisBijdrageService dmfapplBasisBijdrageService, Opper opper, RekenTijd rekenTijd, RegulManager regulManager) {
        this.constantManager = constantManager;
        this.dmfapplBasisBijdrageService = dmfapplBasisBijdrageService;
        this.opper = opper;
        this.rekenTijd = rekenTijd;
        this.regulManager = regulManager;

        beginDatum = rekenTijd.beginDatum;
        eindDatum = rekenTijd.eindDatum;
        Rszppo rszppo = opper.getRszppo();
        vrijstellingTweedePensioenpijler = rszppo.getVrijstellingTweedePensioenpijler();
    }

    @Override
    public void validate() {
        Opdracht opdracht = opper.getOpdracht();
        Hoedanigheid hoedanigheid = opdracht.getHoedanigheid();
        Rszppo rszppo = opper.getRszppo();
        DmfapplWnkengetal werknemersKengetal = rszppo.getWerknemersKengetal();
        WerkgeversCategorie werkgeversCategorie = rszppo.getWerkgeversCategorie();
        Categorie categorie = CategorieFactory.getCategorie(rekenTijd, werkgeversCategorie);
        Statuut statuut = StatuutFactory.create(rekenTijd, rszppo.getStatuutDmfappl());
        DmfapplNotieGepens notieGepensioneerd = rszppo.getNotieGepensioneerd();
        int typeLeerling = rszppo.getTypeLeerling();

        int typeBijdrage = constantManager.getByCodeDatum(Konstanten.KST_TYPE_BIJDRAGE_PENS2, eindDatum).getInteger();
        int doelgroepPens2 = constantManager.getByCodeDatum(Konstanten.KST_DOELGROEP_PENS2, eindDatum).getInteger();
        BigDecimal bijdrageBonusPens2 = constantManager.getByCodeDatum(Konstanten.KST_BIJDRAGE_PENS2B, eindDatum).getProcentFactor();
        BigDecimal bijdrageBonusPens2Perc2 = constantManager.getByCodeDatum(Konstanten.KST_BIJDRAGE_PENS2B_PERC2, eindDatum).getProcentFactor();

        PensioenPijler2TypeBijdrage pensioenPijler2TypeBijdrage = PensioenPijler2TypeBijdrage.getByCode(typeBijdrage);
        boolean typeTweedePensioenPijlerIsGeen = pensioenPijler2TypeBijdrage == PensioenPijler2TypeBijdrage.GEEN;
        if (typeTweedePensioenPijlerIsGeen && vrijstellingTweedePensioenpijler != VrijstelPens2.NVT) {
            BegrotingQueueCalculateFailureLogger.logVrijstellingRegulException(eindDatum, typeBijdrage, vrijstellingTweedePensioenpijler, doelgroepPens2, 85);
            regulManager.doRegulException(opdracht, Regulkode.VRIJSTEL_PENS2);
        } else if (vrijstellingTweedePensioenpijler == VrijstelPens2.BONUSBIJDRAGE
                && (beginDatum.isBefore(START_BONUSBIJDRAGE)
                || (pensioenPijler2TypeBijdrage.isProvantOrEthias())
                || bijdrageBonusPens2.signum() == 0)) {
            BegrotingQueueCalculateFailureLogger.logVrijstellingRegulException(eindDatum, typeBijdrage, vrijstellingTweedePensioenpijler, doelgroepPens2, 91);
            regulManager.doRegulException(opdracht, Regulkode.VRIJSTEL_PENS2);
        } else if (vrijstellingTweedePensioenpijler == VrijstelPens2.BONUSBIJDRAGE2
                && (beginDatum.isBefore(START_BONUSBIJDRAGE)
                || (pensioenPijler2TypeBijdrage.isProvantOrEthias())
                || bijdrageBonusPens2Perc2.signum() == 0)) {
            BegrotingQueueCalculateFailureLogger.logVrijstellingRegulException(eindDatum, typeBijdrage, vrijstellingTweedePensioenpijler, doelgroepPens2, 97);
            regulManager.doRegulException(opdracht, Regulkode.VRIJSTEL_PENS2);
        } else if (vrijstellingTweedePensioenpijler == VrijstelPens2.WEL_VRIJSTELLING && (beginDatum.isBefore(VANAF_2010) || (
                beginDatum.isBefore(VANAF_2007) && typeBijdrage == PensioenPijler2TypeBijdrage.ETHIAS.getCode()))) {
            BegrotingQueueCalculateFailureLogger.logVrijstellingRegulException(eindDatum, typeBijdrage, vrijstellingTweedePensioenpijler, doelgroepPens2, 101);
            regulManager.doRegulException(opdracht, Regulkode.VRIJSTEL_PENS2);
        } else {
            if (rekenTijd.isDmfa()) {
                controleerVrijstelling2dePensioenpijlerDmfaAndere(hoedanigheid, werknemersKengetal, werkgeversCategorie, statuut, notieGepensioneerd,
                        doelgroepPens2, typeTweedePensioenPijlerIsGeen, typeLeerling);
            } else {
                controleerVrijstelling2dePensioenpijlerDmfapplAndere(opdracht, hoedanigheid, werknemersKengetal, werkgeversCategorie, categorie,
                        statuut, notieGepensioneerd, doelgroepPens2, typeTweedePensioenPijlerIsGeen, typeLeerling);
            }
        }
    }

    public void controleerVrijstelling2dePensioenpijlerDmfapplAndere(
            Opdracht opdracht, Hoedanigheid hoedanigheid, DmfapplWnkengetal werknemersKengetal, WerkgeversCategorie werkgeversCategorie, Categorie categorie,
            Statuut statuut, DmfapplNotieGepens notieGepensioneerd, int doelgroepPens2, boolean typeTweedePensioenPijlerIsGeen, int typeLeerling) {
        boolean hoedanigheidStudentOfMonitor = hoedanigheid == Hoedanigheid.STUDENTEN || hoedanigheid == Hoedanigheid.MONITOREN;
        boolean categorieArbeidsregelingPriveOfOpenbaar = categorie.isArbeidsregelingPrive() || categorie.isArbeidsregelingOpenbaar();
        boolean geenVrijstellingGeenTypeTweedePensioenpijler =
                vrijstellingTweedePensioenpijler != VrijstelPens2.WEL_VRIJSTELLING && !typeTweedePensioenPijlerIsGeen;
        if (geenVrijstellingGeenTypeTweedePensioenpijler
                && hoedanigheidStudentOfMonitor
                && categorieArbeidsregelingPriveOfOpenbaar
                && WerknemersKengetalFactory.isNotLeerContract(rekenTijd, werknemersKengetal)) {
            BegrotingQueueCalculateFailureLogger.logVrijstellingRegulException(eindDatum, 0, vrijstellingTweedePensioenpijler, doelgroepPens2, 97);
            regulManager.doRegulException(opdracht, Regulkode.VRIJSTEL_PENS2);
        } else if (!typeTweedePensioenPijlerIsGeen) {
            controleerVrijstelling2dePensioenpijlerDmfapplNietGeen(werknemersKengetal, werkgeversCategorie, statuut, notieGepensioneerd, doelgroepPens2, typeLeerling);
        } else {
            // do nothing
        }

    }

    public void controleerVrijstelling2dePensioenpijlerDmfaAndere(
            Hoedanigheid hoedanigheid, DmfapplWnkengetal werknemersKengetal, WerkgeversCategorie werkgeversCategorie,
            Statuut statuut, DmfapplNotieGepens notieGepensioneerd, int doelgroepPens2, boolean typeTweedePensioenPijlerIsGeen, int typeLeerling) {
        if (hoedanigheid != Hoedanigheid.STUDENTEN && hoedanigheid != Hoedanigheid.MONITOREN && !typeTweedePensioenPijlerIsGeen) {
            controleerVrijstelling2dePensioenpijlerDmfapplNietGeen(werknemersKengetal, werkgeversCategorie, statuut, notieGepensioneerd, doelgroepPens2, typeLeerling);
        }
    }

    public void controleerVrijstelling2dePensioenpijlerDmfapplNietGeen(
            DmfapplWnkengetal werknemersKengetal, WerkgeversCategorie werkgeversCategorie,
            Statuut statuut, DmfapplNotieGepens notieGepensioneerd, int doelgroepPens2, int typeLeerling) {
        List<DmfapplBasisBijdrage> basisBijdragen = dmfapplBasisBijdrageService
                .findByWerkgeversCategorieWerknemersKengetalWerknemersKengetalBijdrage(werkgeversCategorie, werknemersKengetal,
                        WerknemersKengetalMapperFactory.getBijdrageAanvulPensContr(rekenTijd), eindDatum);

        if (basisBijdragen.isEmpty() && vrijstellingTweedePensioenpijler != VrijstelPens2.NVT) {
            BegrotingQueueCalculateFailureLogger.logVrijstellingRegulException(eindDatum, 0, vrijstellingTweedePensioenpijler, doelgroepPens2, 149);
            regulManager.doRegulException(opper.getOpdracht(), Regulkode.VRIJSTEL_PENS2);
        } else {
            if (!basisBijdragen.isEmpty()) {
                controleerVrijstelling2dePensioenpijlerDmfapplNietGeenMetBasisBijdragen(statuut, notieGepensioneerd, doelgroepPens2, typeLeerling);
            }
        }
    }

    private void controleerVrijstelling2dePensioenpijlerDmfapplNietGeenMetBasisBijdragen(
            Statuut statuut, DmfapplNotieGepens notieGepensioneerd, int doelgroepPens2, int typeLeerling) {
        Opdracht opdracht = opper.getOpdracht();
        if (geenPens2(statuut) && vrijstellingTweedePensioenpijler != VrijstelPens2.NVT) {
            BegrotingQueueCalculateFailureLogger.logVrijstellingRegulException(eindDatum, 0, vrijstellingTweedePensioenpijler, doelgroepPens2, 167);
            regulManager.doRegulException(opdracht, Regulkode.VRIJSTEL_PENS2);
        } else if (checkGezondheidSectorNew(statuut) && doelgroepPens2 == DOELGROEP_PENS2_STANDAARD
                && vrijstellingTweedePensioenpijler != VrijstelPens2.WEL_VRIJSTELLING) {
            BegrotingQueueCalculateFailureLogger.logVrijstellingRegulException(eindDatum, 0, vrijstellingTweedePensioenpijler, doelgroepPens2, 171);
            regulManager.doRegulException(opdracht, Regulkode.VRIJSTEL_PENS2);
        } else if (checkGezondheidSectorNew(statuut)
                && doelgroepPens2 == DOELGROEP_PENS2_OOK_GEZONDHEID_SECTOR
                && vrijstellingTweedePensioenpijler == VrijstelPens2.WEL_VRIJSTELLING
                && notieGepensioneerd != DmfapplNotieGepens.GEPENSION && typeLeerling == 0) {
            BegrotingQueueCalculateFailureLogger.logVrijstellingRegulException(eindDatum, 0, vrijstellingTweedePensioenpijler, doelgroepPens2, 179);
            regulManager.doRegulException(opdracht, Regulkode.VRIJSTEL_PENS2);
        }
    }

    private boolean geenPens2(Statuut statuut) {
        return !statuut.komtInAanmerkingPens2() || checkGezondheidSectorOld(statuut);
    }

    private boolean checkGezondheidSectorNew(Statuut statuut) {
        return statuut.isDmfaStatuutGezondheidSector() && !beginDatum.isBefore(START_PENS2_GEZONDHEIDS_SECTOR);
    }

    private boolean checkGezondheidSectorOld(Statuut statuut) {
        return statuut.isDmfaStatuutGezondheidSector() && beginDatum.isBefore(START_PENS2_GEZONDHEIDS_SECTOR);
    }
}
